47	var service = &router.AdmissionService{
48		Path: "/queues/validate",
49		Func: AdmitQueues,
50	
51		Config: config,
52	
53		ValidatingConfig: &whv1.ValidatingWebhookConfiguration{
54			Webhooks: []whv1.ValidatingWebhook{{
55				Name: "validatequeue.volcano.sh",
56				Rules: []whv1.RuleWithOperations{
57					{
58						Operations: []whv1.OperationType{whv1.Create, whv1.Update, whv1.Delete},
59						Rule: whv1.Rule{
60							APIGroups:   []string{schedulingv1beta1.SchemeGroupVersion.Group},
61							APIVersions: []string{schedulingv1beta1.SchemeGroupVersion.Version},
62							Resources:   []string{"queues"},
