72	// AdmitQueues is to admit queues and return response.
73	func AdmitQueues(ar admissionv1.AdmissionReview) *admissionv1.AdmissionResponse {
74		klog.V(3).Infof("Admitting %s queue %s.", ar.Request.Operation, ar.Request.Name)
75	
76		queue, err := schema.DecodeQueue(ar.Request.Object, ar.Request.Resource)
77		if err != nil {
78			return util.ToAdmissionResponse(err)
79		}
80	
81		switch ar.Request.Operation {
82		case admissionv1.Create, admissionv1.Update:
83			err = validateQueue(queue)
84			if err != nil {
85				return util.ToAdmissionResponse(err)
86			}
87			var oldQueue *schedulingv1beta1.Queue
88			if ar.Request.Operation == admissionv1.Update {
89				oldQueue, err = schema.DecodeQueue(ar.Request.OldObject, ar.Request.Resource)
90				if err != nil {
91					return util.ToAdmissionResponse(err)
92				}
93			}
94	
95			if ar.Request.Operation == admissionv1.Create || oldQueue.Spec.Parent != queue.Spec.Parent {
96				err = validateHierarchicalQueue(queue)
97				if err != nil {
98					return util.ToAdmissionResponse(err)
99				}
100			}
101	
102			// Block attribute modifications to root queue on UPDATE
103			if config.EnableRootQueueProtection && ar.Request.Operation == admissionv1.Update && queue.Name == "root" && oldQueue != nil {
104				if !equality.Semantic.DeepEqual(queue.Spec.Capability, oldQueue.Spec.Capability) ||
105					!equality.Semantic.DeepEqual(queue.Spec.Deserved, oldQueue.Spec.Deserved) ||
106					!equality.Semantic.DeepEqual(queue.Spec.Guarantee.Resource, oldQueue.Spec.Guarantee.Resource) {
107					return util.ToAdmissionResponse(fmt.Errorf("root queue's resource attributes (capability, deserved, guarantee) cannot be modified"))
108				}
109			}
110	
111			if needsValidateHierarchicalQueue(queue, oldQueue, ar.Request.Operation) {
112				err = validateHierarchicalQueueResources(queue)
113				if err != nil {
114					return util.ToAdmissionResponse(err)
115				}
116			}
117		case admissionv1.Delete:
118			err = validateQueueDeleting(ar.Request.Name)
119			if err != nil {
120				return util.ToAdmissionResponse(err)
121			}
122		default:
123			return util.ToAdmissionResponse(fmt.Errorf("invalid operation `%s`, "+
124				"expect operation to be `CREATE`, `UPDATE` or `DELETE`", ar.Request.Operation))
125		}
126	
127		return &admissionv1.AdmissionResponse{
128			Allowed: true,
129		}
130	}
