132	func validateQueue(queue *schedulingv1beta1.Queue) error {
133		errs := field.ErrorList{}
134		resourcePath := field.NewPath("requestBody")
135	
136		errs = append(errs, validateResourceQuantityOfQueue(queue.Spec, resourcePath.Child("spec"))...)
137		errs = append(errs, validateStateOfQueue(queue.Status.State, resourcePath.Child("spec").Child("state"))...)
138		errs = append(errs, validateHierarchicalAttributes(queue, resourcePath.Child("metadata").Child("annotations"))...)
139	
140		if len(errs) > 0 {
141			return errs.ToAggregate()
142		}
143	
144		return nil
145	}
146	
147	func validateHierarchicalAttributes(queue *schedulingv1beta1.Queue, fldPath *field.Path) field.ErrorList {
148		errs := field.ErrorList{}
149		hierarchy := queue.Annotations[schedulingv1beta1.KubeHierarchyAnnotationKey]
150		hierarchicalWeights := queue.Annotations[schedulingv1beta1.KubeHierarchyWeightAnnotationKey]
151		if hierarchy != "" || hierarchicalWeights != "" {
152			paths := strings.Split(hierarchy, "/")
153			weights := strings.Split(hierarchicalWeights, "/")
154			// path length must be the same with weights length
155			if len(paths) != len(weights) {
156				return append(errs, field.Invalid(fldPath, hierarchy,
157					fmt.Sprintf("%s must have the same length with %s",
158						schedulingv1beta1.KubeHierarchyAnnotationKey,
159						schedulingv1beta1.KubeHierarchyWeightAnnotationKey,
160					)))
161			}
162	
163			// check weights format
164			for _, weight := range weights {
165				weightFloat, err := strconv.ParseFloat(weight, 64)
166				if err != nil {
167					return append(errs, field.Invalid(fldPath, hierarchicalWeights,
168						fmt.Sprintf("%s in the %s is invalid number: %v",
169							weight, hierarchicalWeights, err,
170						)))
171				}
172				if weightFloat <= 0 {
173					return append(errs, field.Invalid(fldPath, hierarchicalWeights,
174						fmt.Sprintf("%s in the %s must be larger than 0",
175							weight, hierarchicalWeights,
176						)))
177				}
178			}
179	
180			// The node is not allowed to be in the sub path of a node.
181			// For example, a queue with "root/sci" conflicts with a queue with "root/sci/dev"
182			queueList, err := config.QueueLister.List(labels.Everything())
183			if err != nil {
184				return append(errs, field.Invalid(fldPath, hierarchy,
185					fmt.Sprintf("checking %s, list queues failed: %v",
186						schedulingv1beta1.KubeHierarchyAnnotationKey,
187						err,
188					)))
189			}
190			for _, queueInTree := range queueList {
191				hierarchyInTree := queueInTree.Annotations[schedulingv1beta1.KubeHierarchyAnnotationKey]
192				// Add a "/" char to be sure, that we only compare parts that are full nodes.
193				// For example if we have in the cluster queue /root/scidev and wants to create a /root/sci
194				if hierarchyInTree != "" && queue.Name != queueInTree.Name &&
195					strings.HasPrefix(hierarchyInTree, hierarchy+"/") {
196					return append(errs, field.Invalid(fldPath, hierarchy,
197						fmt.Sprintf("%s is not allowed to be in the sub path of %s of queue %s",
198							hierarchy, hierarchyInTree, queueInTree.Name)))
199				}
200			}
201		}
202		return errs
203	}
