205	func validateStateOfQueue(value schedulingv1beta1.QueueState, fldPath *field.Path) field.ErrorList {
206		errs := field.ErrorList{}
207	
208		if len(value) == 0 {
209			return errs
210		}
211	
212		validQueueStates := []schedulingv1beta1.QueueState{
213			schedulingv1beta1.QueueStateOpen,
214			schedulingv1beta1.QueueStateClosed,
215		}
216	
217		for _, validQueue := range validQueueStates {
218			if value == validQueue {
219				return errs
220			}
221		}
222	
223		return append(errs, field.Invalid(fldPath, value, fmt.Sprintf("queue state must be in %v", validQueueStates)))
224	}
