226	// Verify the resource quantity Of Queue and configure the resource quantity as guaranteed ≤ deserved ≤ capability
227	func validateResourceQuantityOfQueue(spec schedulingv1beta1.QueueSpec, fldPath *field.Path) field.ErrorList {
228		errs := field.ErrorList{}
229	
230		if len(spec.Capability) != 0 {
231			for resourceName, quantity := range spec.Capability {
232				errs = append(errs, k8scorevalid.ValidateResourceQuantityValue(k8score.ResourceName(resourceName), quantity, fldPath.Child("capability").Child(resourceName.String()))...)
233			}
234		}
235	
236		if len(spec.Deserved) != 0 {
237			for resourceName, quantity := range spec.Deserved {
238				errs = append(errs, k8scorevalid.ValidateResourceQuantityValue(k8score.ResourceName(resourceName), quantity, fldPath.Child("deserved").Child(resourceName.String()))...)
239			}
240		}
241	
242		if len(spec.Guarantee.Resource) != 0 {
243			for resourceName, guaranteeQ := range spec.Guarantee.Resource {
244				errs = append(errs, k8scorevalid.ValidateResourceQuantityValue(
245					k8score.ResourceName(resourceName), guaranteeQ,
246					fldPath.Child("guarantee").Child("resource").Child(resourceName.String()))...,
247				)
248	
249				desQ, exists := spec.Deserved[resourceName]
250				if !exists {
251					errs = append(errs, field.Invalid(
252						fldPath.Child("deserved").Child(resourceName.String()),
253						"<nil>",
254						fmt.Sprintf("deserved[%s] must be >= guarantee[%s]=%s",
255							resourceName, resourceName, guaranteeQ.String()),
256					))
257					continue
258				}
259	
260				if desQ.Cmp(guaranteeQ) < 0 {
261					errs = append(errs, field.Invalid(
262						fldPath.Child("deserved").Child(resourceName.String()),
263						desQ.String(),
264						fmt.Sprintf("deserved[%s]=%s must be >= guarantee[%s]=%s",
265							resourceName, desQ.String(), resourceName, guaranteeQ.String()),
266					))
267				}
268			}
269		}
270	
271		if len(spec.Deserved) != 0 && len(spec.Capability) != 0 {
272			for resourceName, desQ := range spec.Deserved {
273				capQ, capExists := spec.Capability[resourceName]
274				// If the capability is not configured considers that the capability is not restricted
275				if !capExists {
276					continue
277				}
278	
279				if desQ.Cmp(capQ) > 0 {
280					errs = append(errs, field.Invalid(
281						fldPath.Child("deserved").Child(resourceName.String()),
282						desQ.String(),
283						fmt.Sprintf(
284							"deserved[%s]=%s must be <= capability[%s]=%s",
285							resourceName, desQ.String(), resourceName, capQ.String(),
286						),
287					))
288				}
289			}
290		}
291	
292		return errs
293	}
294	
295	func validateQueueDeleting(queueName string) error {
296		if queueName == "default" {
297			return fmt.Errorf("`%s` queue can not be deleted", "default")
298		}
299	
300		if queueName == "root" {
301			return fmt.Errorf("`%s` queue can not be deleted", "root")
302		}
303	
304		queue, err := config.QueueLister.Get(queueName)
305		if err != nil {
306			return err
307		}
308	
309		// Only check allocated pods if the flag is enabled
310		if config.EnableQueueAllocatedPodsCheck {
311			if allocated, ok := queue.Status.Allocated[v1.ResourcePods]; ok && !allocated.IsZero() {
312				return fmt.Errorf("queue %s cannot be deleted because it has allocated Pods: %d",
313					queue.Name, allocated.Value())
314			}
315		}
316	
317		childQueueNames, err := listQueueChild(queueName)
318		if err != nil {
319			return fmt.Errorf("failed to list child queues: %v", err)
320		}
321	
322		if len(childQueueNames) > 0 {
323			return fmt.Errorf("queue %s can not be deleted because it has %d child queues: %s",
324				queue.Name, len(childQueueNames), strings.Join(childQueueNames, ", "))
325		}
326	
327		klog.V(3).Infof("Validation passed for deleting hierarchical queue %s", queue.Name)
328	
329		return nil
330	}
331	
332	// needsValidateHierarchicalQueue determines if hierarchy resource validation is necessary
333	// Returns true only if:
334	// - Queue is not the root queue itself AND
335	// - Either it's a CREATE operation OR resources (capability/deserved/guarantee) changed on UPDATE OR parent changed on UPDATE
336	func needsValidateHierarchicalQueue(queue, oldQueue *schedulingv1beta1.Queue, operation admissionv1.Operation) bool {
337		// Only the root queue itself should skip validation completely
338		if queue.Name == "root" {
339			return false
340		}
341	
342		// For CREATE operations, always validate
343		if operation == admissionv1.Create {
344			return true
345		}
346	
347		// For UPDATE operations, only validate if resources or parent changed
348		if operation == admissionv1.Update && oldQueue != nil {
349			// Check if parent changed
350			if queue.Spec.Parent != oldQueue.Spec.Parent {
351				return true
352			}
353			// Check if capability changed
354			if !equality.Semantic.DeepEqual(queue.Spec.Capability, oldQueue.Spec.Capability) {
355				return true
356			}
357			// Check if deserved changed
358			if !equality.Semantic.DeepEqual(queue.Spec.Deserved, oldQueue.Spec.Deserved) {
359				return true
360			}
361			// Check if guarantee changed
362			if !equality.Semantic.DeepEqual(queue.Spec.Guarantee.Resource, oldQueue.Spec.Guarantee.Resource) {
363				return true
364			}
365			// No resource or parent changes, skip validation
366			return false
367		}
368	
369		// Default: skip validation
370		return false
371	}
372	
373	func validateHierarchicalQueue(queue *schedulingv1beta1.Queue) error {
374		if queue.Spec.Parent == "" || queue.Spec.Parent == "root" {
375			return nil
376		}
377	
378		// Prevent a queue from using its own name as the parent
379		if queue.Spec.Parent == queue.Name {
380			return fmt.Errorf("queue %s cannot use itself as parent", queue.Name)
381		}
382	
383		//Check whether the queue level depth exceeds the upper limit.
384		if err := validateQueueDepth(queue); err != nil {
385			return err
386		}
387	
388		parentQueue, err := config.QueueLister.Get(queue.Spec.Parent)
389		if err != nil {
390			return fmt.Errorf("failed to get parent queue of queue %s: %v", queue.Name, err)
391		}
392	
393		childQueueNames, err := listQueueChild(parentQueue.Name)
394		if err != nil {
395			return fmt.Errorf("failed to list child queues of queue %s: %v", parentQueue.Name, err)
396		}
397	
398		if len(childQueueNames) == 0 {
399			if allocated, ok := parentQueue.Status.Allocated[v1.ResourcePods]; ok && !allocated.IsZero() {
400				return fmt.Errorf("queue %s cannot be the parent queue of queue %s because it has allocated Pods: %d",
401					parentQueue.Name, queue.Name, allocated.Value())
402			}
403		}
404	
405		klog.V(3).Infof("Validation passed for hierarchical queue %s with parent queue %s",
406			queue.Name, parentQueue.Name)
407		return nil
408	}
409	
410	func listQueueChild(parentQueueName string) ([]string, error) {
411		queueList, err := config.QueueLister.List(labels.Everything())
412		if err != nil {
413			return nil, fmt.Errorf("failed to list queues: %v", err)
414		}
415	
416		childQueueNames := make([]string, 0)
417		for _, childQueue := range queueList {
418			if childQueue.Spec.Parent != parentQueueName {
419				continue
420			}
421			childQueueNames = append(childQueueNames, childQueue.Name)
422		}
423	
424		return childQueueNames, nil
425	}
426	
427	func getSingleResource(r *api.Resource, name v1.ResourceName) float64 {
428		switch name {
429		case v1.ResourceCPU:
430			return r.MilliCPU
431		case v1.ResourceMemory:
432			return r.Memory
433		default:
434			if v, ok := r.ScalarResources[name]; ok {
435				return v
436			}
437		}
438		return 0
439	}
440	
441	// Recursively searches for the ancestor queue that recently defines the capability
442	func findNearestAncestorCapability(q *schedulingv1beta1.Queue, rname v1.ResourceName) (float64, bool) {
443		parent := q.Spec.Parent
444		for parent != "" && parent != "root" {
445			pq, err := config.QueueLister.Get(parent)
446			if err != nil {
447				return 0, false
448			}
449	
450			if pq.Spec.Capability != nil {
451				res := api.NewResource(pq.Spec.Capability)
452				val := getSingleResource(res, rname)
453				if val > 0 {
454					return val, true
455				}
456			}
457	
458			parent = pq.Spec.Parent
459		}
460		return 0, false
461	}
462	
463	// Recursively searches for the maximum capability value of a descendant queue
464	func findSubtreeMaxCapability(q *schedulingv1beta1.Queue, rname v1.ResourceName) float64 {
465		if q.Spec.Capability != nil {
466			res := api.NewResource(q.Spec.Capability)
467			v := getSingleResource(res, rname)
468			if v > 0 {
469				return v
470			}
471		}
472	
473		children, _ := listQueueChild(q.Name)
474		maxV := float64(0)
475		for _, cname := range children {
476			cq, err := config.QueueLister.Get(cname)
477			if err != nil {
478				continue
479			}
480			v := findSubtreeMaxCapability(cq, rname)
481			if v > maxV {
482				maxV = v
483			}
484		}
485	
486		return maxV
487	}
488	
489	func formatResourceWithType(name v1.ResourceName, value float64) string {
490		switch name {
491		case v1.ResourceCPU:
492			q := resource.NewMilliQuantity(int64(value), resource.DecimalSI)
493			return q.String()
494	
495		case v1.ResourceMemory:
496			q := resource.NewQuantity(int64(value), resource.BinarySI)
497			return q.String()
498	
499		default:
500			return fmt.Sprintf("%.2f", value)
501		}
502	}
503	
504	func validateQueueDepth(queue *schedulingv1beta1.Queue) error {
505		depth := 1
506		parent := queue.Spec.Parent
507	
508		for parent != "" && parent != "root" {
509			depth++
510			if depth > config.MaxQueueDepth {
511				return fmt.Errorf("queue %s exceeds the maximum allowed depth of %d", queue.Name, config.MaxQueueDepth)
512			}
513			p, err := config.QueueLister.Get(parent)
514			if err != nil {
515				return fmt.Errorf("failed to get parent queue %s of queue %s: %v",
516					parent, queue.Name, err)
517			}
518			parent = p.Spec.Parent
519		}
520	
521		return nil
522	}
523	
524	// validateHierarchicalQueueResources validates all hierarchy resource constraints for a queue
525	// This function uses informer index for efficient lookups instead of listing all queues
526	// This includes:
527	// - Child's capability <= parent's capability
528	// - Sum of siblings' guarantee/deserved <= parent's limit
529	// - Parent's capability >= each child's capability
530	// - Sum of children's guarantee/deserved <= parent's limit
531	func validateHierarchicalQueueResources(queue *schedulingv1beta1.Queue) error {
532		// If this is a child queue, validate against parent
533		if queue.Spec.Parent != "" && queue.Spec.Parent != "root" {
534			// Get parent queue directly using lister
535			parentQueue, err := config.QueueLister.Get(queue.Spec.Parent)
536			if err != nil {
537				return fmt.Errorf("parent queue %s not found: %v", queue.Spec.Parent, err)
538			}
539	
540			// Check queue's capability <= ancestors's capability
541			if err := validateChildAgainstAncestor(queue); err != nil {
542				return err
543			}
544	
545			// Get siblings using index
546			siblings, err := config.GetQueuesByParent(queue.Spec.Parent)
547			if err != nil {
548				return fmt.Errorf("failed to get sibling queues: %v", err)
549			}
550	
551			// Check sum of all siblings' (including this queue) guarantee/deserved <= parent's limit
552			if err := validateSiblingsSum(queue, parentQueue, siblings); err != nil {
553				return err
554			}
555		}
556	
557		// Get children using index
558		children, err := config.GetQueuesByParent(queue.Name)
559		if err != nil {
560			return fmt.Errorf("failed to get child queues: %v", err)
561		}
562	
563		// If this queue has children, validate all children constraints
564		if len(children) > 0 {
565			if err := validateChildrenConstraints(queue, children); err != nil {
566				return err
567			}
568		}
569	
570		return nil
571	}
572	
573	// validateChildAgainstAncestor validates that child queue's resources don't exceed ancestors's
574	func validateChildAgainstAncestor(child *schedulingv1beta1.Queue) error {
575		if child.Spec.Capability != nil {
576			qRes := api.NewResource(child.Spec.Capability)
577			resKeys := qRes.ResourceNames()
578			for _, r := range resKeys {
579				myVal := getSingleResource(qRes, r)
580				if upLimit, ok := findNearestAncestorCapability(child, r); ok {
581					if myVal > upLimit {
582						return fmt.Errorf("queue %s capability[%s]=%v exceeds its ancestor's capability=%v", child.Name, r, formatResourceWithType(r, myVal), formatResourceWithType(r, upLimit))
583					}
584				}
585			}
586		}
587	
588		return nil
589	}
590	
591	// validateSiblingsSum validates that sum of all sibling queues' resources don't exceed parent's limit
592	// siblings parameter should already be filtered to only include children of the parent queue
593	func validateSiblingsSum(queue, parent *schedulingv1beta1.Queue, siblings []*schedulingv1beta1.Queue) error {
594		totalGuarantee := api.EmptyResource()
595		totalDeserved := api.EmptyResource()
596	
597		parentGuarantee := api.NewResource(parent.Spec.Guarantee.Resource)
598		parentDeserved := api.NewResource(parent.Spec.Deserved)
599	
600		// siblings are already filtered by parent, just exclude self
601		for _, sibling := range siblings {
602			if sibling.Name != queue.Name {
603				totalGuarantee.Add(api.NewResource(sibling.Spec.Guarantee.Resource))
604				if parentGuarantee.LessPartly(totalGuarantee, api.Zero) {
605					return fmt.Errorf("parent queue %s validation failed: sum of children's guarantee (%s) exceeds parent's guarantee limit (%s)",
606						parent.Name, totalGuarantee, parentGuarantee)
607				}
608	
609				totalDeserved.Add(api.NewResource(sibling.Spec.Deserved))
610				if parentDeserved.LessPartly(totalDeserved, api.Zero) {
611					return fmt.Errorf("parent queue %s validation failed: sum of children's deserved (%s) exceeds parent's deserved limit (%s)",
612						parent.Name, totalDeserved, parentDeserved)
613				}
614			}
615		}
616	
617		// Add the current queue's resources
618		totalGuarantee.Add(api.NewResource(queue.Spec.Guarantee.Resource))
619		if parentGuarantee.LessPartly(totalGuarantee, api.Zero) {
620			return fmt.Errorf("parent queue %s validation failed: sum of children's guarantee (%s) exceeds parent's guarantee limit (%s)",
621				parent.Name, totalGuarantee, parentGuarantee)
622		}
623	
624		totalDeserved.Add(api.NewResource(queue.Spec.Deserved))
625		if parentDeserved.LessPartly(totalDeserved, api.Zero) {
626			return fmt.Errorf("parent queue %s validation failed: sum of children's deserved (%s) exceeds parent's deserved limit (%s)",
627				parent.Name, totalDeserved, parentDeserved)
628		}
629	
630		return nil
631	}
632	
633	// validateChildrenConstraints validates that parent's resources are sufficient for all children
634	func validateChildrenConstraints(parent *schedulingv1beta1.Queue, children []*schedulingv1beta1.Queue) error {
635		totalGuarantee := api.EmptyResource()
636		totalDeserved := api.EmptyResource()
637	
638		// Recursively checks child queues as parent only when queue is nil and parentQueue.Spec.Capability exists
639		if parent.Spec.Capability != nil {
640			// Obtains all resource fields defined by the parent capability
641			pRes := api.NewResource(parent.Spec.Capability)
642			resKeys := pRes.ResourceNames()
643			for _, r := range resKeys {
644				parentVal := getSingleResource(pRes, r)
645	
646				// Maximum value of capability in descendant
647				childMax := float64(0)
648	
649				// Traverse all subqueues
650				for _, cq := range children {
651					// Obtains the maximum capability of the sub-queue sub-tree
652					v := findSubtreeMaxCapability(cq, r)
653					if v > childMax {
654						childMax = v
655					}
656				}
657	
658				// The capability of the parent must be greater than or equal to the maximum capability of the subtree
659				if parentVal < childMax {
660					return fmt.Errorf("queue %s capability[%s]=%v is smaller than its descendants' max capability=%v",
661						parent.Name, r, formatResourceWithType(r, parentVal), formatResourceWithType(r, childMax))
662				}
663			}
664		}
665	
666		parentGuarantee := api.NewResource(parent.Spec.Guarantee.Resource)
667		parentDeserved := api.NewResource(parent.Spec.Deserved)
668	
669		for _, child := range children {
670			// Accumulate children's guarantee and deserved
671			totalGuarantee.Add(api.NewResource(child.Spec.Guarantee.Resource))
672			if parentGuarantee.LessPartly(totalGuarantee, api.Zero) {
673				return fmt.Errorf("queue %s validation failed: sum of children's guarantee (%s) exceeds parent's guarantee limit (%s)",
674					parent.Name, totalGuarantee, parentGuarantee)
675			}
676	
677			totalDeserved.Add(api.NewResource(child.Spec.Deserved))
678			if parentDeserved.LessPartly(totalDeserved, api.Zero) {
679				return fmt.Errorf("queue %s validation failed: sum of children's deserved (%s) exceeds parent's deserved limit (%s)",
680					parent.Name, totalDeserved, parentDeserved)
681			}
682		}
683	
684		return nil
685	}
686	
